import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [newRecord, setNewRecord] = useState({
    date: new Date().toISOString().split('T')[0],
    FEV1: '',
    FVC: '',
    PEF: '',
    respiratory_rate: '',
    pulse: '',
    cough: '0',
    breathlessness: '0',
    wheezing: '0',
    chest_tightness: '0',
    nighttime_awakenings: '',
    medicine: ''
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const fetchRecords = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
        if (!response.ok) {
          throw new Error('Failed to fetch records');
        }
        const data = await response.json();
        setIndicatorsData(data);
      } catch (error) {
        console.error('Error fetching records:', error);
        setError('Failed to load records');
      }
    };

    fetchRecords();
  }, [navigate]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewRecord(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...newRecord,
          user_id: parseInt(user_id)
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to add record');
      }

      const data = await response.json();
      setSuccess('Record added successfully');

      // Refresh records
      const recordsResponse = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      const recordsData = await recordsResponse.json();
      setIndicatorsData(recordsData);

      // Clear form
      setNewRecord({
        date: new Date().toISOString().split('T')[0],
        FEV1: '',
        FVC: '',
        PEF: '',
        respiratory_rate: '',
        pulse: '',
        cough: '0',
        breathlessness: '0',
        wheezing: '0',
        chest_tightness: '0',
        nighttime_awakenings: '',
        medicine: ''
      });
    } catch (err) {
      setError(err.message);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <form onSubmit={handleSubmit} className="new-record-form">
          <div className="form-row">
            <input
              type="date"
              name="date"
              value={newRecord.date}
              onChange={handleInputChange}
              required
            />
            <input
              type="number"
              name="FEV1"
              value={newRecord.FEV1}
              onChange={handleInputChange}
              placeholder="FEV1"
              step="0.1"
              required
            />
            <input
              type="number"
              name="FVC"
              value={newRecord.FVC}
              onChange={handleInputChange}
              placeholder="FVC"
              step="0.1"
              required
            />
            <input
              type="number"
              name="PEF"
              value={newRecord.PEF}
              onChange={handleInputChange}
              placeholder="PEF"
              required
            />
            <input
              type="number"
              name="respiratory_rate"
              value={newRecord.respiratory_rate}
              onChange={handleInputChange}
              placeholder="Respiratory Rate"
              required
            />
            <input
              type="number"
              name="pulse"
              value={newRecord.pulse}
              onChange={handleInputChange}
              placeholder="Pulse"
              required
            />
            <select
              name="cough"
              value={newRecord.cough}
              onChange={handleInputChange}
              required
            >
              <option value="0">No Cough</option>
              <option value="1">Mild</option>
              <option value="2">Moderate</option>
              <option value="3">Severe</option>
            </select>
            <select
              name="breathlessness"
              value={newRecord.breathlessness}
              onChange={handleInputChange}
              required
            >
              <option value="0">No</option>
              <option value="1">Yes</option>
            </select>
            <select
              name="wheezing"
              value={newRecord.wheezing}
              onChange={handleInputChange}
              required
            >
              <option value="0">No</option>
              <option value="1">Yes</option>
            </select>
            <select
              name="chest_tightness"
              value={newRecord.chest_tightness}
              onChange={handleInputChange}
              required
            >
              <option value="0">No</option>
              <option value="1">Yes</option>
            </select>
            <input
              type="number"
              name="nighttime_awakenings"
              value={newRecord.nighttime_awakenings}
              onChange={handleInputChange}
              placeholder="Nighttime Awakenings"
              min="0"
              required
            />
            <input
              type="text"
              name="medicine"
              value={newRecord.medicine}
              onChange={handleInputChange}
              placeholder="Medicine"
              required
            />
            <button type="submit" className="add-record-button">Add Record</button>
          </div>
        </form>

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row, index) => (
                <tr key={index}>
                  <td>{new Date(row.date).toLocaleDateString()}</td>
                  <td>{row.FEV1}</td>
                  <td>{row.FVC}</td>
                  <td>{row.PEF}</td>
                  <td>{row.respiratory_rate}</td>
                  <td>{row.pulse}</td>
                  <td>{row.cough === 0 ? 'No' : row.cough === 1 ? 'Mild' : row.cough === 2 ? 'Moderate' : 'Severe'}</td>
                  <td>{row.breathlessness === 0 ? 'No' : 'Yes'}</td>
                  <td>{row.wheezing === 0 ? 'No' : 'Yes'}</td>
                  <td>{row.chest_tightness === 0 ? 'No' : 'Yes'}</td>
                  <td>{row.nighttime_awakenings}</td>
                  <td>{row.medicine}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default RecordingIndicators;
